use std::fs::File;
use std::io::{self, Read};
use std::error::Error;

struct ParserError { 
    message: String,
    source: io::Error,
}

impl From<io::Error> for ParserError {
    fn from(err: io::Error) -> Self {
        ParserError {
            message: format!("Failed to process file structure."),
            source: err,
        }
    }
}

#[derive(Debug)]
struct DataFormatError { 
    line_number: usize,
    content: String,
}

impl std::fmt::Display for DataFormatError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Bad data found on line {}: '{}'", self.line_number, self.content)
    }
}

impl Error for DataFormatError {}

fn parse_data(path: &str) -> Result<String, Box<dyn Error>> {
    let mut file = File::open(path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    let lines: Vec<&str> = contents.trim().split('n').collect();

    for (i, &line) in lines.iter().enumerate() {
        if line.contains("MALFORMED") {
            return Err(Box::new(DataFormatError { 
                line_number: i + 1,
                content: line.to_string(),
            }));
        }
    }

    Ok(format!("Successfully parsed {} lines.", lines.len()))
}

fn main() {
    let result = std::panic::catch_unwind(|| {
        parse_data("test_input.txt")
    });

    if let Err(e) = result {
        eprintln!("A fatal error occurred during parsing: {:?}", e);
    }
}

use miette::Diagnostic;
use std::fs::File;
use std::io::{self, BufRead, BufReader};

struct SensorDataProcessor {
    log_path: String,
}

impl SensorDataProcessor {
    fn new(log_path: &str) -> Self {
        SensorDataProcessor { 
            log_path: log_path.to_string()
        }
    }

    fn process(&self) -> Result<String, Box<dyn std::error::Error>> {
        let file = File::open(&self.log_path)?;
        let reader = BufReader::new(file);

        let mut error_count = 0;
        let mut line_buffer = String::new();

        for line in reader.lines() {
            line_buffer.clear();
            match line {
                Ok(l) => {
                    line_buffer = l;
                    if line_buffer.contains("ERROR_SIGNATURE") {
                        error_count += 1;
                    }
                },
                Err(e) => return Err(Box::new(e)),
            }
        }

        Ok(format!("Processing complete. Found {} errors.", error_count))
    }
}

fn main() {
    let processor = SensorDataProcessor::new("sensor.log");
    match processor.process() {
        Ok(summary) => println!("Success: {}", summary),
        Err(e) => eprintln!("Failure during processing: {}", e),
    }
}
